parameters.jsCode:
return items.map(item => {
  const data = item.json;

  const now = new Date();
  const fechaArchivo = now.getFullYear().toString() +
    String(now.getMonth() + 1).padStart(2, '0') +
    String(now.getDate()).padStart(2, '0') +
    String(now.getHours()).padStart(2, '0');

  const empresa = (data["Nombre de la Empresa o Emprendimiento"] || "SinNombre")
    .trim()
    .replace(/\s+/g, '_')
    .replace(/[^a-zA-Z0-9_áéíóúÁÉÍÓÚñÑ]/g, '');

  return {
    json: {
      nombre: data["Nombre completo"],
      empresa: data["Nombre de la Empresa o Emprendimiento"],
      contacto: data["Número de contacto"],
      correo: data["Correo electrónico"],
      fechaActual: now.toISOString(),
      nombreArchivoPdf: `Diagnostico_${empresa}_${fechaArchivo}`,
      respuestas: {
        P1: data["P1: ¿En qué etapa se encuentra tu proyecto o negocio?"],
        P2: data["P2: ¿A qué sector pertenece tu actividad principal?"],
        P3: data["P3: ¿En qué subsector te ubicas principalmente?"],
        P4: data["P4: ¿Cuántas personas forman parte de tu equipo actualmente?"],
        P5: data["P5: ¿Cuál es su volumen anual de ingresos expresados en dólares?"],
        P6: data["P6 (Gestión Financiera): Cuando revisas tus cuentas a fin de mes, ¿qué suele suceder?"],
        P7: data["P7 (Gestión Comercial): ¿Cómo llegan los clientes a tu negocio?"],
        P8: data["P8 (Gestión de Procesos): Si mañana tuvieras que ausentarte por 15 días, ¿qué pasaría con el negocio?"],
        P9: data["P9 (Gestión Tecnológica): ¿Qué tan \"digital\" es tu operación diaria?"],
        P10: data["P10 (Gestión de Personas): ¿Cómo te sientes respecto a tu equipo de trabajo?"],
        P11: data["P11: ¿Cuál de estas situaciones te quita más energía actualmente?"],
        P12: data["P12 (Dolor Mayor): ¿Cuál es el problema #1 que, si lográramos resolver hoy mismo, cambiaría por completo el rumbo de tu negocio?"]
      }
    }
  };
});

const iteracion = $json["iteracion"] || 0;
if (iteracion >= 3) {
  // escalar a revisión manual
  return [{ json: { ...items[0].json, escalar: true } }];
}
return [{ json: { ...items[0].json, iteracion: iteracion + 1 } }];

